SELECT member_id, COUNT(DISTINCT role_id) as distinct_role_count
FROM member_role_assignments
GROUP BY member_id;

SELECT m.member_id, m.username, m.email, m.failed_login_attempts, m.account_lockout_date
FROM members m
WHERE m.failed_login_attempts > 5 AND m.account_lockout_date < date('now');

SELECT plan_name, price 
FROM membership_plans 
WHERE price BETWEEN 50 AND 100;

SELECT COUNT(*)
FROM members
WHERE member_id = 0;

SELECT member_id
FROM members
WHERE (
    strftime('%Y-%m-%d', 'now') - strftime('%Y-%m-%d', last_login_date) > 90
) AND (
    member_id NOT IN (
        SELECT member_id
        FROM password_resets
        WHERE strftime('%Y-%m-%d', 'now') - strftime('%Y-%m-%d', reset_date) <= 6
    )
);

SELECT username
FROM members
WHERE last_login_date < date('now', '-1 month');
